@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> Optional[ProductType]:
        db = info.context["db"]
        return db.query(Product).filter(Product.id == id).first()
    
    @strawberry.field
    def products(self, info) -> List[ProductType]:
        db = info.context["db"]
        return db.query(Product).all()
    
    @strawberry.field
    def category(self, info, id: int) -> Optional[CategoryType]:
        db = info.context["db"]
        return db.query(Category).filter(Category.id == id).first()
    
    @strawberry.field
    def categories(self, info) -> List[CategoryType]:
        db = info.context["db"]
        return db.query(Category).all()

# Create database and tables
engine = create_engine("sqlite:///products.db")
Base.metadata.create_all(engine)
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)

# FastAPI app
app = FastAPI()
graphql_app = GraphQLRouter(schema=strawberry.Schema(query=Query))

@app.middleware("http")
async def db_session_middleware(request, call_next):
    request.state.db = SessionLocal()
    try:
        response = await call_next(request)
    finally:
        request.state.db.close()
    return response

app.include_router(graphql_app, prefix="/graphql")

# Context for GraphQL
def get_db(request):
    return request.state.db

# Add context to GraphQL schema
Query.__strawberry_definition__.context = get_db